import numpy as np

def dueling_network_forward(x, shared_weights, shared_bias,
                           value_weights, value_bias,
                           advantage_weights, advantage_bias,
                           aggregation='mean'):
    batch_size = len(x)
    hidden_dim = len(shared_bias)
    num_actions = len(advantage_bias)

    # Shared feature layer: ReLU(x @ W + b)
    features = [[0.0] * hidden_dim for _ in range(batch_size)]
    for i in range(batch_size):
        for j in range(hidden_dim):
            val = shared_bias[j]
            for k in range(len(x[i])):
                val += x[i][k] * shared_weights[k][j]
            features[i][j] = max(0.0, val)

    # Value stream: V(s), shape (batch, 1)
    values = [0.0] * batch_size
    for i in range(batch_size):
        val = value_bias[0]
        for j in range(hidden_dim):
            val += features[i][j] * value_weights[j][0]
        values[i] = val

    # Advantage stream: A(s,a), shape (batch, num_actions)
    advantages = [[0.0] * num_actions for _ in range(batch_size)]
    for i in range(batch_size):
        for a in range(num_actions):
            val = advantage_bias[a]
            for j in range(hidden_dim):
                val += features[i][j] * advantage_weights[j][a]
            advantages[i][a] = val

    # Aggregation: Q = V + (A - baseline)
    q_values = [[0.0] * num_actions for _ in range(batch_size)]
    for i in range(batch_size):
        if aggregation == 'mean':
            baseline = sum(advantages[i]) / num_actions
        else:  # max
            baseline = max(advantages[i])
        for a in range(num_actions):
            q_values[i][a] = values[i] + (advantages[i][a] - baseline)

    return np.array(q_values)
